# Checks autogenerated packages from a dpk file. Also check the dpr/res/dfm copy

. test.setup
$registry = "tmstest\packages-from-dpk"
Set-AlternateRegistryKey -RegKey $registry -RegisterAllDelphiVersions $true

tms config-write -p:configuration-for-all-products:replace-delphi-versions=[delphi7,delphi12,delphi13] -p:configuration-for-all-products:platforms=[win32intel,win64intel] -p:configuration-for-all-products:options:skip-register=false

tms build

$checkFiles = @(
    "dcr\rectangles.dcr",
    "FRes.dfm",
    "triangles.dcr"
)
foreach ($delphi in @("23.0", "37.0")) {
     Write-Host "Checking files for platform '$delphi'." -ForegroundColor Green
     foreach ($file in $checkFiles) {
        if (-Not (Test-Path "testpkg\resourceful\packages\d11+\$delphi\Win32\Release\$file")) {
            throw "The file '$file' does not exist."
        }
    }
}

$originalLocation = Get-Location
Set-Location testapp

bds -ProjectFile "testapp.dproj" -RegistryKey $registry

.\Win32\Debug\testapp.exe | Assert-ValueIs "616/616"

Set-Location $originalLocation
tms build -unregister